    primaryProvider: 'openrouter',
    primaryModel: 'meta-llama/llama-3.3-70b-instruct:free',
    fallbackEnabled: true,
    fallbackOrder: DEFAULT_FALLBACK_ORDER,
    notifyOnFallback: true,
  };

  return new AIProviderRouter(config, onFallback);
}

